"use client";

import { Suspense, useActionState, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { login } from "../actions";
import { safeNextPath } from "@/lib/auth/safe-next";
import GoogleSignInButton from "@/components/auth/google-sign-in-button";
import DevLoginHelper from "@/components/dev-login-helper";

export default function LoginPage() {
  // useSearchParams() requires a Suspense boundary for static-render bailout.
  return (
    <Suspense>
      <LoginPageContent />
    </Suspense>
  );
}

function LoginPageContent() {
  const [state, action, pending] = useActionState(login, null);
  const [email, setEmail] = useState("");
  const searchParams = useSearchParams();
  const next = safeNextPath(searchParams.get("next")) ?? undefined;

  return (
    <div className="flex flex-col items-center w-full max-w-sm">
      <Card className="w-full max-w-sm">
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>SailBook</CardTitle>
          <CardDescription>Sign in to your account</CardDescription>
        </div>
        <Image
          src="/logo.png"
          alt="Simply Sailing"
          width={80}
          height={80}
          className="h-20 w-auto"
          priority
        />
      </CardHeader>
      <CardContent className="space-y-4 pb-0">
        <GoogleSignInButton next={next} />
        <div className="flex items-center gap-3 py-1">
          <div className="h-px flex-1 bg-border" />
          <span className="text-xs text-muted-foreground">or</span>
          <div className="h-px flex-1 bg-border" />
        </div>
      </CardContent>
      <form action={action} noValidate>
        {next ? <input type="hidden" name="next" value={next} /> : null}
        <CardContent className="space-y-4">
          {state?.error && (
            <p className="text-sm text-destructive">{state.error}</p>
          )}
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              name="email"
              type="email"
              required
              autoComplete="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label htmlFor="password">Password</Label>
              <Link
                href="/forgot-password"
                className="text-xs text-muted-foreground underline underline-offset-4 hover:text-foreground"
              >
                Forgot password?
              </Link>
            </div>
            <Input
              id="password"
              name="password"
              type="password"
              required
              autoComplete="current-password"
            />
          </div>
        </CardContent>
        <CardFooter className="flex flex-col gap-3 pt-4">
          <Button type="submit" className="w-full" disabled={pending}>
            {pending ? "Signing in…" : "Sign in"}
          </Button>
          <p className="text-sm text-muted-foreground text-center">
            No account?{" "}
            <Link
              href="/register"
              className="underline underline-offset-4 hover:text-foreground"
            >
              Register
            </Link>
          </p>
        </CardFooter>
      </form>
      </Card>
      <DevLoginHelper />
    </div>
  );
}

import { Suspense } from 'react'
import { createClient } from '@/lib/supabase/server'
import RegisterForm from './register-form'

export default async function RegisterPage() {
  const supabase = await createClient()

  const { data: codes } = await supabase
    .from('codes')
    .select('value, label, description')
    .eq('category', 'experience_level')
    .eq('is_active', true)
    .order('sort_order')

  // RegisterForm uses useSearchParams() — Suspense bailout required for build.
  return (
    <Suspense>
      <RegisterForm experienceCodes={codes ?? []} />
    </Suspense>
  )
}

'use server'

import { createClient } from '@/lib/supabase/server'
import { safeNextPath } from '@/lib/auth/safe-next'
import { friendlyPasswordError, validatePassword } from '@/lib/auth/password-rules'
import { redirect } from 'next/navigation'

export async function login(_: unknown, formData: FormData) {
  const supabase = await createClient()

  const { data, error } = await supabase.auth.signInWithPassword({
    email: formData.get('email') as string,
    password: formData.get('password') as string,
  })

  if (error) return { error: error.message }

  const safeNext = safeNextPath(formData.get('next') as string | null)
  if (safeNext) redirect(safeNext)

  const meta = (data.user?.user_metadata ?? {}) as Record<string, unknown>
  if (meta.is_admin) redirect('/admin/dashboard')
  if (meta.is_instructor) redirect('/instructor/dashboard')
  redirect('/student/dashboard')
}

export async function register(_: unknown, formData: FormData) {
  const supabase = await createClient()

  const email = formData.get('email') as string
  const password = formData.get('password') as string
  const firstName = formData.get('firstName') as string
  const lastName = formData.get('lastName') as string
  const phone = (formData.get('phone') as string)?.trim() || ''
  const experienceLevel = (formData.get('experienceLevel') as string) || ''
  const instructorNotes = (formData.get('instructorNotes') as string)?.trim() || ''

  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL ?? 'http://localhost:3000'

  const next = safeNextPath(formData.get('next') as string | null) ?? '/student/dashboard'

  // Mirror the Supabase password policy server-side for a clearer error path.
  const passwordError = validatePassword(password)
  if (passwordError) return { error: passwordError }

  // All profile fields ride on raw_user_meta_data. The handle_new_user trigger
  // (migration 20260429020252) reads them and inserts the profile row.
  const { error } = await supabase.auth.signUp({
    email,
    password,
    options: {
      data: {
        is_admin: false,
        is_instructor: false,
        is_student: true,
        first_name: firstName,
        last_name: lastName,
        phone,
        experience_level: experienceLevel,
        instructor_notes: instructorNotes,
      },
      emailRedirectTo: `${siteUrl}/auth/callback?next=${encodeURIComponent(next)}`,
    },
  })

  if (error) return { error: friendlyPasswordError(error.message) }

  redirect(`/register/check-email?email=${encodeURIComponent(email)}`)
}

export async function signInWithGoogle(_: unknown, formData: FormData) {
  const supabase = await createClient()
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL ?? 'http://localhost:3000'

  // Caller can pass ?next=/foo to send the user somewhere after sign-in
  // (e.g. the invite-acceptance page). Default to the student dashboard.
  const next = safeNextPath(formData.get('next') as string | null) ?? '/student/dashboard'

  const { data, error } = await supabase.auth.signInWithOAuth({
    provider: 'google',
    options: {
      redirectTo: `${siteUrl}/auth/callback?next=${encodeURIComponent(next)}`,
    },
  })

  if (error) return { error: error.message }
  if (!data.url) return { error: 'Could not start Google sign-in.' }

  redirect(data.url)
}

export async function signOut() {
  const supabase = await createClient()
  await supabase.auth.signOut()
  redirect('/login')
}

export async function requestPasswordReset(_: unknown, formData: FormData) {
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL
  if (!siteUrl) return { error: 'Password reset is not available. Contact support.' }

  const supabase = await createClient()
  const email = formData.get('email') as string

  const { error } = await supabase.auth.resetPasswordForEmail(email, {
    redirectTo: `${siteUrl}/reset-password`,
  })

  if (error) return { error: error.message }
  return { error: null }
}

export async function updatePassword(_: unknown, formData: FormData) {
  const supabase = await createClient()
  const password = formData.get('password') as string

  const passwordError = validatePassword(password)
  if (passwordError) return { error: passwordError }

  const { data: { user }, error } = await supabase.auth.updateUser({ password })

  if (error) return { error: friendlyPasswordError(error.message) }

  const meta = (user?.user_metadata ?? {}) as Record<string, unknown>
  if (meta.is_admin) redirect('/admin/dashboard')
  if (meta.is_instructor) redirect('/instructor/dashboard')
  redirect('/student/dashboard')
}

// Logged-in password change. Distinct from updatePassword (recovery flow):
// re-authenticates the current user with their current password before
// allowing the change. DEC-015 form-action shape: string | null.
export async function changePassword(_: unknown, formData: FormData): Promise<string | null> {
  const currentPassword = (formData.get('current_password') as string) ?? ''
  const newPassword = (formData.get('new_password') as string) ?? ''
  const confirmPassword = (formData.get('confirm_password') as string) ?? ''

  if (!currentPassword || !newPassword || !confirmPassword) {
    return 'All fields are required.'
  }
  if (newPassword !== confirmPassword) {
    return 'New password and confirmation do not match.'
  }
  const passwordError = validatePassword(newPassword)
  if (passwordError) return passwordError

  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user?.email) return 'You are not signed in.'

  // Re-auth check: signInWithPassword fails if the current password is wrong.
  // On success it rotates the session — same user, fresh tokens.
  const { error: reauthError } = await supabase.auth.signInWithPassword({
    email: user.email,
    password: currentPassword,
  })
  if (reauthError) return 'Current password is incorrect.'

  const { error: updateError } = await supabase.auth.updateUser({ password: newPassword })
  if (updateError) return friendlyPasswordError(updateError.message)

  return null
}

import { NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { safeNextPath } from '@/lib/auth/safe-next'

export async function GET(request: Request) {
  const url = new URL(request.url)
  const code = url.searchParams.get('code')
  const next = safeNextPath(url.searchParams.get('next')) ?? '/student/dashboard'

  // Trust the Host header only when it matches an allow-list — the canonical
  // site host (production) or localhost/127.0.0.1 any-port (dev: Hetzner's :3000
  // AND VS Code Remote-SSH's random forwarded port like :55934 both work). A
  // spoofed Host falls back to NEXT_PUBLIC_SITE_URL so it can't be used to
  // redirect users off-site post-auth.
  const hostHeader = request.headers.get('host') ?? ''
  const proto = request.headers.get('x-forwarded-proto') ?? 'http'
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL
  const siteHost = siteUrl ? new URL(siteUrl).host : null
  const isAllowedHost =
    hostHeader === siteHost ||
    /^(localhost|127\.0\.0\.1)(:\d+)?$/.test(hostHeader)
  const baseUrl = isAllowedHost
    ? `${proto}://${hostHeader}`
    : (siteUrl ?? url.origin)

  if (!code) {
    return NextResponse.redirect(`${baseUrl}/login?error=missing_code`)
  }

  const supabase = await createClient()
  const { error } = await supabase.auth.exchangeCodeForSession(code)

  if (error) {
    return NextResponse.redirect(`${baseUrl}/login?error=invalid_link`)
  }

  return NextResponse.redirect(`${baseUrl}${next}`)
}

