import { test, expect } from '@playwright/test'

test.describe('?next= param forwarding through auth pages', () => {
  test('login page passes ?next= to register link', async ({ page }) => {
    await page.goto('/login?next=/student/courses/123')
    await page.getByRole('link', { name: 'Register' }).click()
    expect(page.url()).toContain('/register')
    expect(page.url()).toContain('next=%2Fstudent%2Fcourses%2F123')
  })

  test('register page passes ?next= back to sign-in link', async ({ page }) => {
    await page.goto('/register?next=/student/courses/123')
    await page.getByRole('link', { name: 'Sign in' }).click()
    expect(page.url()).toContain('/login')
    expect(page.url()).toContain('next=%2Fstudent%2Fcourses%2F123')
  })

  test('login page register link works without ?next=', async ({ page }) => {
    await page.goto('/login')
    await page.getByRole('link', { name: 'Register' }).click()
    expect(page.url()).toContain('/register')
    expect(page.url()).not.toContain('next=')
  })
})

