'use client'

import { useTransition, useState } from 'react'
import { useRouter } from 'next/navigation'
import { updateProfile } from '@/actions/profiles'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useUnsavedChanges } from '@/hooks/use-unsaved-changes'

type Profile = {
  id: string
  first_name: string
  last_name: string
  email: string
  phone: string | null
  experience_level: string | null
  asa_number: string | null
  is_active: boolean
  is_student: boolean
  is_instructor: boolean
  is_member: boolean
}

type ExperienceCode = {
  value: string
  label: string
  description: string | null
}

export default function ProfileEditForm({
  profile,
  returnPath,
  experienceCodes = [],
}: {
  profile: Profile
  returnPath: string
  experienceCodes?: ExperienceCode[]
}) {
  const router = useRouter()
  const [pending, startTransition] = useTransition()
  const [error, setError] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const { confirmDiscard } = useUnsavedChanges(isDirty)

  function handleSubmit(formData: FormData) {
    setError(null)

    if (profile.is_instructor && profile.is_active && formData.get('is_active') === 'false') {
      if (!window.confirm('Deactivating this instructor will remove them from all assigned courses and sessions. Continue?')) {
        return
      }
    }

    startTransition(async () => {
      const result = await updateProfile(formData)
      if (result?.error) {
        setError(result.error)
      } else {
        router.push(returnPath)
      }
    })
  }

  return (
    <form action={handleSubmit} className="space-y-6 max-w-lg" onChange={() => setIsDirty(true)}>
      <input type="hidden" name="id" value={profile.id} />
      <input type="hidden" name="return_path" value={returnPath} />

      {error && (
        <p className="text-sm text-destructive bg-destructive/10 border border-destructive/20 rounded-lg px-3 py-2">
          {error}
        </p>
      )}

      <div className="space-y-2">
        <Label htmlFor="email">Email</Label>
        <Input id="email" value={profile.email} disabled className="bg-muted" />
        <p className="text-xs text-muted-foreground">Email is managed through Supabase Auth and cannot be changed here.</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label htmlFor="first_name">First Name</Label>
          <Input id="first_name" name="first_name" defaultValue={profile.first_name} required />
        </div>
        <div className="space-y-2">
          <Label htmlFor="last_name">Last Name</Label>
          <Input id="last_name" name="last_name" defaultValue={profile.last_name} required />
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="phone">Phone</Label>
        <Input id="phone" name="phone" defaultValue={profile.phone ?? ''} />
      </div>

      {profile.is_student && (
        <div className="space-y-2">
          <Label htmlFor="asa_number">ASA Number</Label>
          <Input id="asa_number" name="asa_number" defaultValue={profile.asa_number ?? ''} placeholder="e.g. 123456" maxLength={20} />
        </div>
      )}

      {profile.is_student && (
        <div className="space-y-2">
          <Label htmlFor="experience_level">Experience Level</Label>
          <select
            id="experience_level"
            name="experience_level"
            defaultValue={profile.experience_level ?? '—'}
            className="flex h-9 w-full rounded-md border border-input bg-background text-foreground px-3 py-1 text-sm shadow-xs transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
          >
            <option value="—">Not set</option>
            {experienceCodes.map((code) => (
              <option key={code.value} value={code.value}>
                {code.label}
              </option>
            ))}
          </select>
        </div>
      )}

      {profile.is_student && (
        <div className="flex items-center gap-3">
          <input
            type="checkbox"
            id="is_member"
            name="is_member"
            defaultChecked={profile.is_member}
            className="h-4 w-4 rounded border border-input accent-primary"
          />
          <Label htmlFor="is_member" className="cursor-pointer">Simply Sailing Member (member pricing at checkout)</Label>
        </div>
      )}

      <div className="space-y-2">
        <Label htmlFor="is_active">Status</Label>
        <select
          id="is_active"
          name="is_active"
          defaultValue={profile.is_active ? 'true' : 'false'}
          className="flex h-9 w-full rounded-md border border-input bg-background text-foreground px-3 py-1 text-sm shadow-xs transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
        >
          <option value="true">Active</option>
          <option value="false">Inactive</option>
        </select>
      </div>

      <div className="flex gap-3">
        <Button type="submit" disabled={pending}>
          {pending ? 'Saving…' : 'Save Changes'}
        </Button>
        <Button type="button" variant="ghost" onClick={() => { if (confirmDiscard()) router.push(returnPath) }}>
          Cancel
        </Button>
      </div>
    </form>
  )
}

'use client'

import { Fragment, useState, useTransition } from 'react'
import Link from 'next/link'
import { fmtTime } from '@/lib/utils'
import { updateSession, cancelSession, deleteSession } from '@/actions/sessions'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'
import { TableRow, TableCell } from '@/components/ui/table'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import SessionInstructorSelect from '@/components/admin/session-instructor-select'
import MakeupSessionForm from '@/components/admin/makeup-session-form'
import { useUnsavedChanges } from '@/hooks/use-unsaved-changes'

type SessionData = {
  id: string
  date: string
  start_time: string
  end_time: string
  location: string | null
  instructor_id: string | null
  status: 'scheduled' | 'completed' | 'cancelled'
  cancel_reason: string | null
  instructor: { first_name: string; last_name: string } | null
}

type InstructorOption = { id: string; first_name: string; last_name: string }

export default function SessionRow({
  session,
  courseId,
  instructors,
  missedCount,
  linkedCount,
}: {
  session: SessionData
  courseId: string
  instructors: InstructorOption[]
  missedCount: number
  linkedCount: number
}) {
  const [isEditing, setIsEditing] = useState(false)
  const [editError, setEditError] = useState<string | null>(null)
  const [actionError, setActionError] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [pending, startTransition] = useTransition()
  const isCancelled = session.status === 'cancelled'
  const { confirmDiscard } = useUnsavedChanges(isDirty)

  function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault()
    const formData = new FormData(e.currentTarget)
    setEditError(null)
    startTransition(async () => {
      const result = await updateSession(session.id, courseId, formData)
      if (result === null) {
        setIsEditing(false)
        setIsDirty(false)
      } else {
        setEditError(result)
      }
    })
  }

  function handleCancel() {
    const reason = prompt('Cancel reason (e.g., weather, instructor unavailable):')
    if (reason === null) return
    setActionError(null)
    startTransition(async () => {
      const result = await cancelSession(session.id, courseId, reason)
      if (result.error) setActionError(result.error)
    })
  }

  function handleDelete() {
    if (!window.confirm('Delete this session? This cannot be undone.')) return
    setActionError(null)
    startTransition(async () => {
      const result = await deleteSession(session.id, courseId)
      if (result.error) setActionError(result.error)
    })
  }

  return (
    <Fragment>
      <TableRow data-session-id={session.id}>
        <TableCell>
          {new Date(session.date + 'T00:00:00').toLocaleDateString('en-US', {
            weekday: 'short',
            month: 'short',
            day: 'numeric',
          })}
        </TableCell>
        <TableCell className="whitespace-nowrap hidden sm:table-cell">
          {fmtTime(session.start_time)} – {fmtTime(session.end_time)}
        </TableCell>
        <TableCell className="hidden md:table-cell">{session.location ?? '—'}</TableCell>
        <TableCell className="hidden sm:table-cell">
          <SessionInstructorSelect
            sessionId={session.id}
            courseId={courseId}
            instructorId={session.instructor_id}
            instructors={instructors}
          />
        </TableCell>
        <TableCell>
          <Badge
            variant={
              session.status === 'scheduled'
                ? 'ok'
                : isCancelled
                ? 'alert'
                : 'neutral'
            }
            title={isCancelled && session.cancel_reason ? session.cancel_reason : undefined}
          >
            {session.status}
          </Badge>
        </TableCell>
        <TableCell>
          <div className="flex items-center gap-2">
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="sm" disabled={pending} aria-label="Session actions">
                  •••
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                {!isCancelled && (
                  <DropdownMenuItem
                    onSelect={() => {
                      if (isEditing && !confirmDiscard()) return
                      setIsEditing((v) => !v)
                      setEditError(null)
                      setIsDirty(false)
                    }}
                  >
                    {isEditing ? 'Close' : 'Edit'}
                  </DropdownMenuItem>
                )}
                <DropdownMenuItem asChild>
                  <Link href={`/admin/courses/${courseId}/sessions/${session.id}/attendance`}>
                    Attendance
                  </Link>
                </DropdownMenuItem>
                {!isCancelled && (
                  <DropdownMenuItem onSelect={handleCancel}>
                    Cancel session
                  </DropdownMenuItem>
                )}
                <DropdownMenuSeparator />
                <DropdownMenuItem
                  onSelect={handleDelete}
                  variant="destructive"
                >
                  Delete
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
            {actionError && <p className="text-xs text-destructive">{actionError}</p>}
          </div>
        </TableCell>
      </TableRow>

      {isEditing && (
        <TableRow>
          <TableCell colSpan={6} className="bg-muted/30">
            <form onSubmit={handleSubmit} className="space-y-3 py-2" onChange={() => setIsDirty(true)}>
              {editError && <p className="text-sm text-destructive">{editError}</p>}
              <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
                <div className="space-y-1.5">
                  <Label>Date</Label>
                  <Input
                    type="date"
                    name="date"
                    required
                    defaultValue={session.date}
                  />
                </div>
                <div className="space-y-1.5">
                  <Label>Start</Label>
                  <Input
                    type="time"
                    name="start_time"
                    required
                    defaultValue={session.start_time.slice(0, 5)}
                  />
                </div>
                <div className="space-y-1.5">
                  <Label>End</Label>
                  <Input
                    type="time"
                    name="end_time"
                    required
                    defaultValue={session.end_time.slice(0, 5)}
                  />
                </div>
              </div>
              <div className="space-y-1.5">
                <Label>Location</Label>
                <Input
                  name="location"
                  defaultValue={session.location ?? ''}
                  placeholder="e.g. Dock A, Edgewater"
                />
              </div>
              <div className="flex gap-2">
                <Button type="submit" size="sm" disabled={pending}>
                  {pending ? 'Saving…' : 'Save'}
                </Button>
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  onClick={() => {
                    if (!confirmDiscard()) return
                    setIsEditing(false)
                    setEditError(null)
                    setIsDirty(false)
                  }}
                >
                  Cancel
                </Button>
              </div>
            </form>
          </TableCell>
        </TableRow>
      )}

      {isCancelled && (
        <TableRow>
          <TableCell colSpan={6} className="bg-muted/30">
            <MakeupSessionForm
              originalSessionId={session.id}
              courseId={courseId}
              defaultStartTime={session.start_time}
              defaultEndTime={session.end_time}
              defaultLocation={session.location}
              missedCount={missedCount}
              linkedCount={linkedCount}
            />
          </TableCell>
        </TableRow>
      )}
    </Fragment>
  )
}

'use client'

import { useActionState, useState, useTransition } from 'react'
import { useFormStatus } from 'react-dom'
import { useRouter } from 'next/navigation'
import { adminEnrollStudent } from '@/actions/enrollments'
import { MANUAL_PAYMENT_METHODS } from '@/lib/constants'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'

type Student = { id: string; first_name: string; last_name: string; email: string }

function SubmitButton() {
  const { pending } = useFormStatus()
  return (
    <Button type="submit" size="sm" disabled={pending}>
      {pending ? 'Enrolling...' : 'Enroll'}
    </Button>
  )
}

export default function AdminEnrollStudentPanel({
  courseId,
  coursePriceCents,
  students,
}: {
  courseId: string
  coursePriceCents: number | null
  students: Student[]
}) {
  const router = useRouter()
  const [open, setOpen] = useState(false)
  const [, startTransition] = useTransition()
  const [error, action] = useActionState(
    async (prev: string | null, formData: FormData) => {
      const result = await adminEnrollStudent(prev, formData)
      if (result === null) {
        setOpen(false)
        startTransition(() => router.refresh())
      }
      return result
    },
    null,
  )

  const defaultAmount = coursePriceCents != null
    ? (coursePriceCents / 100).toFixed(2)
    : ''

  if (!open) {
    return (
      <Button variant="outline" size="sm" onClick={() => setOpen(true)}>
        Enroll Student
      </Button>
    )
  }

  return (
    <div className="rounded-lg border bg-muted/40 p-4">
      <h3 className="text-sm font-medium mb-3">Enroll Student</h3>
      <form action={action} className="space-y-3">
        <input type="hidden" name="course_id" value={courseId} />

        {error && <p className="text-sm text-destructive">{error}</p>}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="space-y-1.5">
            <Label>Student</Label>
            <Select name="student_id" required>
              <SelectTrigger>
                <SelectValue placeholder="Select student" />
              </SelectTrigger>
              <SelectContent>
                {students.map((s) => (
                  <SelectItem key={s.id} value={s.id}>
                    {s.last_name}, {s.first_name} — {s.email}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <Label>Payment method</Label>
            <Select name="payment_method" defaultValue="cash">
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {MANUAL_PAYMENT_METHODS.map((m) => (
                  <SelectItem key={m} value={m}>
                    {m === 'stripe_manual' ? 'Stripe (manual)' : m.charAt(0).toUpperCase() + m.slice(1)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>

        <div className="space-y-1.5 max-w-36">
          <Label htmlFor="amount">Amount ($)</Label>
          <Input
            id="amount"
            name="amount"
            type="number"
            min="0"
            step="0.01"
            defaultValue={defaultAmount}
            placeholder="0.00"
          />
        </div>

        <div className="flex gap-2 pt-1">
          <SubmitButton />
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => setOpen(false)}
          >
            Cancel
          </Button>
        </div>
      </form>
    </div>
  )
}

'use client'

import { useActionState, useEffect, useRef, useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { updateStudentProfile } from '@/actions/profiles'

type ExperienceCode = {
  value: string
  label: string
  description: string | null
}

type Profile = {
  first_name: string
  last_name: string
  phone: string | null
  asa_number: string | null
  experience_level: string | null
  instructor_notes: string | null
}

export default function StudentAccountForm({
  profile,
  experienceCodes,
}: {
  profile: Profile
  experienceCodes: ExperienceCode[]
}) {
  const [state, action, pending] = useActionState(updateStudentProfile, null)

  // DEC-015 form actions return `string | null` — null is success, string is
  // an error. Both null-on-success and null-on-mount look the same, so derive
  // a "just succeeded" flag from the pending → idle transition with state=null.
  const [hasSubmitted, setHasSubmitted] = useState(false)
  const prevPending = useRef(false)
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    if (prevPending.current && !pending) setHasSubmitted(true)
    prevPending.current = pending
  }, [pending])

  const showSuccess = hasSubmitted && state === null && !pending

  return (
    <form action={action} className="space-y-5 max-w-md">
      {state && <p className="text-sm text-destructive">{state}</p>}
      {showSuccess && <p className="text-sm text-primary">Profile updated.</p>}

      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-2">
          <Label htmlFor="first_name">First name</Label>
          <Input
            id="first_name"
            name="first_name"
            defaultValue={profile.first_name}
            required
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="last_name">Last name</Label>
          <Input
            id="last_name"
            name="last_name"
            defaultValue={profile.last_name}
            required
          />
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="phone">Phone</Label>
        <Input
          id="phone"
          name="phone"
          type="tel"
          autoComplete="tel"
          defaultValue={profile.phone ?? ''}
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="asa_number">ASA number</Label>
        <Input
          id="asa_number"
          name="asa_number"
          defaultValue={profile.asa_number ?? ''}
          placeholder="Optional"
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="experience_level">Sailing experience</Label>
        <select
          id="experience_level"
          name="experience_level"
          defaultValue={profile.experience_level ?? ''}
          className="flex h-9 w-full rounded-md border border-input bg-background text-foreground px-3 py-1 text-sm shadow-xs transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
        >
          <option value="">Select experience level</option>
          {experienceCodes.map((code) => (
            <option key={code.value} value={code.value}>
              {code.description ? `${code.label} — ${code.description}` : code.label}
            </option>
          ))}
        </select>
      </div>

      <div className="space-y-2">
        <Label htmlFor="instructor_notes">
          Note for your instructor{' '}
          <span className="text-muted-foreground font-normal">(optional)</span>
        </Label>
        <textarea
          id="instructor_notes"
          name="instructor_notes"
          rows={4}
          defaultValue={profile.instructor_notes ?? ''}
          className="flex w-full rounded-md border border-input bg-background text-foreground px-3 py-2 text-sm shadow-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring resize-none"
          placeholder="Prior sailing experience, medical conditions, seasickness, etc."
        />
      </div>

      <Button type="submit" disabled={pending}>
        {pending ? 'Saving…' : 'Save changes'}
      </Button>
    </form>
  )
}

