'use client'

import { useActionState, useState } from 'react'
import { addSession } from '@/actions/sessions'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useUnsavedChanges } from '@/hooks/use-unsaved-changes'

export default function AddSessionForm({ courseId }: { courseId: string }) {
  const action = addSession.bind(null, courseId)
  const [error, formAction, pending] = useActionState(action, null)
  const [open, setOpen] = useState(false)
  const [isDirty, setIsDirty] = useState(false)
  const { confirmDiscard } = useUnsavedChanges(isDirty && open)
  const [startTime, setStartTime] = useState('08:00')
  const [endTime, setEndTime] = useState('16:00')

  if (!open) {
    return (
      <Button type="button" variant="ghost" size="sm" onClick={() => setOpen(true)}>
        + Add Session
      </Button>
    )
  }

  return (
    <form action={formAction} className="space-y-3" onChange={() => setIsDirty(true)}>
      {error && <p className="text-sm text-destructive">{error}</p>}
      <div className="grid grid-cols-3 gap-3">
        <div className="space-y-1.5">
          <Label>Date</Label>
          <Input type="date" name="date" required />
        </div>
        <div className="space-y-1.5">
          <Label>Start</Label>
          <Input type="time" name="start_time" required value={startTime} onChange={(e) => setStartTime(e.target.value)} />
        </div>
        <div className="space-y-1.5">
          <Label>End</Label>
          <Input type="time" name="end_time" required value={endTime} onChange={(e) => setEndTime(e.target.value)} />
        </div>
      </div>
      <div className="space-y-1.5">
        <Label>Location</Label>
        <Input name="location" placeholder="e.g. Dock A, Edgewater" />
      </div>
      <div className="flex gap-2">
        <Button type="submit" size="sm" disabled={pending}>
          {pending ? 'Adding…' : 'Add Session'}
        </Button>
        <Button type="button" variant="ghost" size="sm" onClick={() => { if (confirmDiscard()) { setOpen(false); setIsDirty(false) } }}>
          Cancel
        </Button>
      </div>
    </form>
  )
}

'use client'

import { useActionState } from 'react'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { updateAdminNotificationPreferences } from '@/actions/notification-preferences'
import type { AdminNotificationEvent } from '@/lib/notifications/preferences'

type NormalizedPrefs = Record<AdminNotificationEvent, { sms: boolean; email: boolean }>

const EVENT_LABELS: Record<AdminNotificationEvent, { title: string; description: string }> = {
  admin_enrollment_alert: {
    title: 'New enrollment alert',
    description: 'Sent when a student finishes payment and confirms their seat in a course.',
  },
  admin_low_enrollment: {
    title: 'Low enrollment warning',
    description: 'Daily reminder for any active course under half-full within 14 days of its first session.',
  },
}

export default function NotificationPreferencesForm({
  initialPrefs,
}: {
  initialPrefs: NormalizedPrefs
}) {
  const [state, action, pending] = useActionState(
    updateAdminNotificationPreferences,
    null,
  )

  return (
    <form action={action} className="space-y-6 max-w-xl">
      {state && <p className="text-sm text-destructive">{state}</p>}

      {(Object.keys(EVENT_LABELS) as AdminNotificationEvent[]).map((event) => {
        const labels = EVENT_LABELS[event]
        const prefs = initialPrefs[event]
        return (
          <fieldset key={event} className="space-y-2 rounded-md border p-4">
            <legend className="px-1 text-sm font-medium">{labels.title}</legend>
            <p className="text-xs text-muted-foreground">{labels.description}</p>
            <div className="flex flex-wrap gap-x-6 gap-y-2 pt-2">
              <Label
                htmlFor={`${event}__sms`}
                className="flex items-center gap-2 text-sm font-normal cursor-pointer"
              >
                <input
                  id={`${event}__sms`}
                  name={`${event}__sms`}
                  type="checkbox"
                  defaultChecked={prefs.sms}
                  className="size-4 rounded border-input accent-primary"
                />
                SMS
              </Label>
              <Label
                htmlFor={`${event}__email`}
                className="flex items-center gap-2 text-sm font-normal cursor-pointer"
              >
                <input
                  id={`${event}__email`}
                  name={`${event}__email`}
                  type="checkbox"
                  defaultChecked={prefs.email}
                  className="size-4 rounded border-input accent-primary"
                />
                Email
              </Label>
            </div>
          </fieldset>
        )
      })}

      <Button type="submit" disabled={pending}>
        {pending ? 'Saving…' : 'Save preferences'}
      </Button>
    </form>
  )
}

'use client'

import { useActionState, useEffect, useRef, useState } from 'react'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { updateStudentNotificationPreferences } from '@/actions/notification-preferences'

type Prefs = { sms: boolean; email: boolean }

export default function NotificationPreferencesSection({
  initialPrefs,
}: {
  initialPrefs: Prefs
}) {
  const [state, action, pending] = useActionState(
    updateStudentNotificationPreferences,
    null,
  )

  // Same DEC-015 pattern as the profile form: derive a transient success
  // banner from the pending → idle transition with state=null.
  const [hasSubmitted, setHasSubmitted] = useState(false)
  const prevPending = useRef(false)
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    if (prevPending.current && !pending) setHasSubmitted(true)
    prevPending.current = pending
  }, [pending])

  const showSuccess = hasSubmitted && state === null && !pending

  return (
    <form action={action} className="space-y-4 max-w-md">
      <div>
        <h2 className="text-lg font-semibold">Notifications</h2>
        <p className="text-sm text-muted-foreground">
          Choose how you hear about enrollments, cancellations, makeups, and reminders.
        </p>
      </div>

      {state && <p className="text-sm text-destructive">{state}</p>}
      {showSuccess && <p className="text-sm text-primary">Preferences saved.</p>}

      <div className="space-y-2 rounded-md border p-4">
        <Label
          htmlFor="student_sms"
          className="flex items-center gap-2 text-sm font-normal cursor-pointer"
        >
          <input
            id="student_sms"
            name="student_sms"
            type="checkbox"
            defaultChecked={initialPrefs.sms}
            className="size-4 rounded border-input accent-primary"
          />
          Receive SMS notifications
        </Label>
        <Label
          htmlFor="student_email"
          className="flex items-center gap-2 text-sm font-normal cursor-pointer"
        >
          <input
            id="student_email"
            name="student_email"
            type="checkbox"
            defaultChecked={initialPrefs.email}
            className="size-4 rounded border-input accent-primary"
          />
          Receive email notifications
        </Label>
      </div>

      <Button type="submit" disabled={pending}>
        {pending ? 'Saving…' : 'Save preferences'}
      </Button>
    </form>
  )
}

