"use client";

import { Suspense, useActionState, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { login } from "../actions";
import { safeNextPath } from "@/lib/auth/safe-next";
import GoogleSignInButton from "@/components/auth/google-sign-in-button";
import DevLoginHelper from "@/components/dev-login-helper";

export default function LoginPage() {
  // useSearchParams() requires a Suspense boundary for static-render bailout.
  return (
    <Suspense>
      <LoginPageContent />
    </Suspense>
  );
}

function LoginPageContent() {
  const [state, action, pending] = useActionState(login, null);
  const [email, setEmail] = useState("");
  const searchParams = useSearchParams();
  const next = safeNextPath(searchParams.get("next")) ?? undefined;

  return (
    <div className="flex flex-col items-center w-full max-w-sm">
      <Card className="w-full max-w-sm">
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>SailBook</CardTitle>
          <CardDescription>Sign in to your account</CardDescription>
        </div>
        <Image
          src="/logo.png"
          alt="Simply Sailing"
          width={80}
          height={80}
          className="h-20 w-auto"
          priority
        />
      </CardHeader>
      <CardContent className="space-y-4 pb-0">
        <GoogleSignInButton next={next} />
        <div className="flex items-center gap-3 py-1">
          <div className="h-px flex-1 bg-border" />
          <span className="text-xs text-muted-foreground">or</span>
          <div className="h-px flex-1 bg-border" />
        </div>
      </CardContent>
      <form action={action} noValidate>
        {next ? <input type="hidden" name="next" value={next} /> : null}
        <CardContent className="space-y-4">
          {state?.error && (
            <p className="text-sm text-destructive">{state.error}</p>
          )}
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              name="email"
              type="email"
              required
              autoComplete="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label htmlFor="password">Password</Label>
              <Link
                href="/forgot-password"
                className="text-xs text-muted-foreground underline underline-offset-4 hover:text-foreground"
              >
                Forgot password?
              </Link>
            </div>
            <Input
              id="password"
              name="password"
              type="password"
              required
              autoComplete="current-password"
            />
          </div>
        </CardContent>
        <CardFooter className="flex flex-col gap-3 pt-4">
          <Button type="submit" className="w-full" disabled={pending}>
            {pending ? "Signing in…" : "Sign in"}
          </Button>
          <p className="text-sm text-muted-foreground text-center">
            No account?{" "}
            <Link
              href={next ? `/register?next=${next}` : "/register"}
              className="underline underline-offset-4 hover:text-foreground"
            >
              Register
            </Link>
          </p>
        </CardFooter>
      </form>
      </Card>
      <DevLoginHelper />
    </div>
  );
}

'use client'

import { useActionState, useEffect, useRef, useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { updateStudentProfile } from '@/actions/profiles'

type ExperienceCode = {
  value: string
  label: string
  description: string | null
}

type Profile = {
  first_name: string
  last_name: string
  phone: string | null
  asa_number: string | null
  experience_level: string | null
  instructor_notes: string | null
}

export default function StudentAccountForm({
  profile,
  experienceCodes,
}: {
  profile: Profile
  experienceCodes: ExperienceCode[]
}) {
  const [state, action, pending] = useActionState(updateStudentProfile, null)

  // DEC-015 form actions return `string | null` — null is success, string is
  // an error. Both null-on-success and null-on-mount look the same, so derive
  // a "just succeeded" flag from the pending → idle transition with state=null.
  const [hasSubmitted, setHasSubmitted] = useState(false)
  const prevPending = useRef(false)
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    if (prevPending.current && !pending) setHasSubmitted(true)
    prevPending.current = pending
  }, [pending])

  const showSuccess = hasSubmitted && state === null && !pending

  return (
    <form action={action} className="space-y-5 max-w-md">
      {state && <p className="text-sm text-destructive">{state}</p>}
      {showSuccess && <p className="text-sm text-primary">Profile updated.</p>}

      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-2">
          <Label htmlFor="first_name">First name</Label>
          <Input
            id="first_name"
            name="first_name"
            defaultValue={profile.first_name}
            required
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor="last_name">Last name</Label>
          <Input
            id="last_name"
            name="last_name"
            defaultValue={profile.last_name}
            required
          />
        </div>
      </div>

      <div className="space-y-2">
        <Label htmlFor="phone">Phone</Label>
        <Input
          id="phone"
          name="phone"
          type="tel"
          autoComplete="tel"
          defaultValue={profile.phone ?? ''}
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="asa_number">ASA number</Label>
        <Input
          id="asa_number"
          name="asa_number"
          defaultValue={profile.asa_number ?? ''}
          placeholder="Optional"
        />
      </div>

      <div className="space-y-2">
        <Label htmlFor="experience_level">Sailing experience</Label>
        <select
          id="experience_level"
          name="experience_level"
          defaultValue={profile.experience_level ?? ''}
          className="flex h-9 w-full rounded-md border border-input bg-background text-foreground px-3 py-1 text-sm shadow-xs transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
        >
          <option value="">Select experience level</option>
          {experienceCodes.map((code) => (
            <option key={code.value} value={code.value}>
              {code.description ? `${code.label} — ${code.description}` : code.label}
            </option>
          ))}
        </select>
      </div>

      <div className="space-y-2">
        <Label htmlFor="instructor_notes">
          Note for your instructor{' '}
          <span className="text-muted-foreground font-normal">(optional)</span>
        </Label>
        <textarea
          id="instructor_notes"
          name="instructor_notes"
          rows={4}
          defaultValue={profile.instructor_notes ?? ''}
          className="flex w-full rounded-md border border-input bg-background text-foreground px-3 py-2 text-sm shadow-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring resize-none"
          placeholder="Prior sailing experience, medical conditions, seasickness, etc."
        />
      </div>

      <Button type="submit" disabled={pending}>
        {pending ? 'Saving…' : 'Save changes'}
      </Button>
    </form>
  )
}

'use client'

import { useActionState, useState } from 'react'
import { addSession } from '@/actions/sessions'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useUnsavedChanges } from '@/hooks/use-unsaved-changes'

export default function AddSessionForm({ courseId }: { courseId: string }) {
  const action = addSession.bind(null, courseId)
  const [error, formAction, pending] = useActionState(action, null)
  const [open, setOpen] = useState(false)
  const [isDirty, setIsDirty] = useState(false)
  const { confirmDiscard } = useUnsavedChanges(isDirty && open)
  const [startTime, setStartTime] = useState('08:00')
  const [endTime, setEndTime] = useState('16:00')

  if (!open) {
    return (
      <Button type="button" variant="ghost" size="sm" onClick={() => setOpen(true)}>
        + Add Session
      </Button>
    )
  }

  return (
    <form action={formAction} className="space-y-3" onChange={() => setIsDirty(true)}>
      {error && <p className="text-sm text-destructive">{error}</p>}
      <div className="grid grid-cols-3 gap-3">
        <div className="space-y-1.5">
          <Label>Date</Label>
          <Input type="date" name="date" required />
        </div>
        <div className="space-y-1.5">
          <Label>Start</Label>
          <Input type="time" name="start_time" required value={startTime} onChange={(e) => setStartTime(e.target.value)} />
        </div>
        <div className="space-y-1.5">
          <Label>End</Label>
          <Input type="time" name="end_time" required value={endTime} onChange={(e) => setEndTime(e.target.value)} />
        </div>
      </div>
      <div className="space-y-1.5">
        <Label>Location</Label>
        <Input name="location" placeholder="e.g. Dock A, Edgewater" />
      </div>
      <div className="flex gap-2">
        <Button type="submit" size="sm" disabled={pending}>
          {pending ? 'Adding…' : 'Add Session'}
        </Button>
        <Button type="button" variant="ghost" size="sm" onClick={() => { if (confirmDiscard()) { setOpen(false); setIsDirty(false) } }}>
          Cancel
        </Button>
      </div>
    </form>
  )
}

